        System.out.print("Please enter the letters that need to be encrypted:");
        Scanner sc = new Scanner(System.in);
        String password = sc.next();
        String encrypted = encrypt(password);
        System.out.println("After encryption：" + encrypted);
    }

    public static String encrypt(String password) {
        StringBuilder encryptedText = new StringBuilder();
        for (int i = 0; i < password.length(); i++) {
            char c = password.charAt(i);
            if (Character.isLetter(c)) {
                if (Character.isLowerCase(c)) {
                    c = (char) ('z' - (c - 'a'));
                } 
            }
            encryptedText.append(c);
        }
        return encryptedText.toString();
    }
}

import java.util.Scanner;

public class EA2 {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Please enter your name:");
        String name = scanner.nextLine();

        System.out.print("Please enter plain text：");
        String plaintext = scanner.nextLine();

        String ciphertext = encrypt(name, plaintext);
        System.out.println("Cipher text：" + ciphertext);

        scanner.close();
    }

    public static String encrypt(String name, String plaintext) {
        StringBuilder sb = new StringBuilder();
        int nameIndex = 0;

        for (int i = 0; i < plaintext.length(); i++) {
            char c = plaintext.charAt(i);

            if (Character.isLetter(c)) {
                sb.append(c);

                if (nameIndex >= name.length()) {
                    nameIndex = 0;
                }

                char keyChar = name.charAt(nameIndex);
                sb.append(keyChar);
                nameIndex++;
            } else {
                sb.append(c);
            }
        }

        return sb.toString();
    }
}

