            System.out.print("Enter your name: ");
            String name = scanner.nextLine();

            String result = insertionEncode(name, plaintext);
            System.out.println("Ciphertext: " + result);
        } else if (choice.equalsIgnoreCase("c")) {
            // 解密方法c：姓名插入解密
            System.out.print("c. Expension Method - Decode, please provide the Ciphertext: ");
            String name = scanner.nextLine();

            System.out.print("Enter the name: ");
            String ciphertext = scanner.nextLine();

            String result = insertionDecode(ciphertext, name );
            System.out.println(result);
        } else {
            System.out.println("Invalid choice. Please select a, b, or c.");
        }

        scanner.close();
    }

    public static String encrypt(String plaintext) {
        StringBuilder ciphertext = new StringBuilder();
        for (int i = 0; i < plaintext.length(); i++) {
            char c = plaintext.charAt(i);
            if (c >= 'a' && c <= 'z') {
                // 将小写字母进行替换加密（a变为z，b变为y，依此类推）
                c = (char) ('z' - (c - 'a'));
            }
            ciphertext.append(c);
            if (c == ' ') {
                // 在加密结果中保留空格
                ciphertext.append(' ');
            }
        }
        return ciphertext.toString();
    }

    public static String insertionEncode(String name, String plaintext) {
        StringBuilder sb = new StringBuilder();
        int nameIndex = 0;

        for (int i = 0; i < plaintext.length(); i++) {
            char c = plaintext.charAt(i);

            if (Character.isLetter(c)) {
                sb.append(c);

                if (nameIndex >= name.length()) {
                    // 当姓名中的字符插入完毕时，重新循环使用姓名中的字符
                    nameIndex = 0;
                }

                char keyChar = name.charAt(nameIndex);
                sb.append(keyChar);
                nameIndex++;
            } else {
                sb.append(c);
            }
        }

        return sb.toString();
    }

    public static String insertionDecode(String name, String ciphertext) {
        StringBuilder sb = new StringBuilder();

        for (int i = 0; i < ciphertext.length(); i += 2) {
            char c = ciphertext.charAt(i);

            if (Character.isLetter(c)) {
                sb.append(c);
            }
        }

        return sb.toString();
    }
}
